package main

import (
	"encoding/xml"
	"fmt"
	"io/ioutil"
)

type Config struct {
	XMLName xml.Name `xml:"config"`
	Settings []Setting `xml:"setting"`
}

type Setting struct {
	Name  string `xml:"name,attr"`
	Value string `xml:",chardata"`
}

func parseConfigFile(filePath string) (*Config, error) {
	xmlFile, err := ioutil.ReadFile(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to read XML file: %v", err)
	}

	var config Config
	err = xml.Unmarshal(xmlFile, &config)
	if err != nil {
		return nil, fmt.Errorf("failed to unmarshal XML: %v", err)
	}

	return &config, nil
}

func main() {
	configPath := "path/to/config.xml"
	config, err := parseConfigFile(configPath)
	if err != nil {
		fmt.Printf("Error parsing config file: %v\n", err)
		return
	}

	for _, setting := range config.Settings {
		fmt.Printf("Setting: %s = %s\n", setting.Name, setting.Value)
	}
}